    96→     || (defined(__INTEGRITY))\
    97→     || (defined(__vms))\
    98→     || (defined(__QNXNTO__))
    99→      const char * c_str = std::strerror( ev );
   100→      return  c_str
   101→        ? std::string( c_str )
   102→        : unknown_err;
   103→  # else  // use strerror_r
   104→      char buf[64];
   105→      char * bp = buf;
   106→      std::size_t sz = sizeof(buf);
   107→  #  if defined(__CYGWIN__) || defined(__USE_GNU)
